# Create a security profile with web content filtering policies
# Security profiles group filtering policies and are assigned to users/groups via CA

$profile = @{
    displayName = 'Block-High-Risk-Internet'
    description = 'Block malware, phishing, and CIPA categories for all employees'
    state = 'enabled'
    priority = 100
} | ConvertTo-Json

$created = Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/beta/networkAccess/filteringProfiles' `
  -Body $profile

Write-Host "Created profile: $($created.id)"

# Add a web category filtering policy to the profile
$policy = @{
    '@odata.type' = '#microsoft.graph.networkaccess.webCategoryFilteringPolicy'
    displayName = 'Block Malware Categories'
    action = 'block'
    webCategories = @(
        @{ name = 'malware' }
        @{ name = 'phishing' }
        @{ name = 'botnet' }
    )
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method POST `
  -Uri "https://graph.microsoft.com/beta/networkAccess/filteringProfiles/$($created.id)/policies" `
  -Body $policy

# Add an FQDN-based filtering policy — block specific domains
$fqdnPolicy = @{
    '@odata.type' = '#microsoft.graph.networkaccess.fqdnFilteringPolicy'
    displayName   = 'Block Known C2 Domains'
    action        = 'block'
    fqdns = @(
        @{ value = 'malicious-site.example.com' }
        @{ value = '*.evilcdn.example.net' }
    )
} | ConvertTo-Json -Depth 5

# Attach to existing security profile
Invoke-MgGraphRequest -Method POST `
  -Uri "https://graph.microsoft.com/beta/networkAccess/filteringProfiles/<profile-id>/policies" `
  -Body $fqdnPolicy

# Or add an ALLOW override for a blocked category (e.g. allow security research tools)
$allowFqdn = @{
    '@odata.type' = '#microsoft.graph.networkaccess.fqdnFilteringPolicy'
    displayName   = 'Allow Security Research Tools'
    action        = 'allow'
    priority      = 50  # lower = higher priority; evaluated before block rules
    fqdns = @( @{ value = 'shodan.io' } )
} | ConvertTo-Json -Depth 5

# Assign a security profile to users via Conditional Access
# The CA policy sets the Global Secure Access security profile as a session control

$caPolicy = @{
    displayName = 'GSA-Internet-Block-High-Risk'
    state = 'enabled'
    conditions = @{
        users = @{ includeGroups = @('<group-id>') }
        applications = @{ includeApplications = @('All') }
    }
    sessionControls = @{
        globalSecureAccessFilteringProfile = @{
            isEnabled = $true
            profileId = '<filtering-profile-id>'
        }
    }
} | ConvertTo-Json -Depth 10

Invoke-MgGraphRequest -Method POST `
  -Uri 'https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies' `
  -Body $caPolicy

# Configure Tenant Restrictions v2 via security profile
# Prevents users from signing in to external (non-corporate) tenants
$trPolicy = @{
    '@odata.type' = '#microsoft.graph.networkaccess.tenantRestrictionPolicy'
    displayName   = 'Block External Tenant Sign-In'
    action        = 'block'
    tenantRestrictions = @{
        mode = 'blockAll'
        allowedTenants = @(
            @{ tenantId = '<contoso-tenant-id>'; displayName = 'Contoso Corp' }
            @{ tenantId = '<partner-tenant-id>'; displayName = 'Partner Corp' }
        )
    }
} | ConvertTo-Json -Depth 10

# Attach to the security profile
Invoke-MgGraphRequest -Method POST `
  -Uri "https://graph.microsoft.com/beta/networkAccess/filteringProfiles/<profile-id>/policies" `
  -Body $trPolicy

# Configure traffic bypass rules — exempt specific IPs/FQDNs from tunnelling
# Use case: internal tools that should not traverse the SSE edge

# Add a bypass rule to the Internet Access forwarding profile
$bypass = @{
    destinations = @(
        @{ '@odata.type' = '#microsoft.graph.networkaccess.fqdnFilteringRule'; value = 'internal-tool.corp.local' }
        @{ '@odata.type' = '#microsoft.graph.networkaccess.ipSubnetFilteringRule'; value = '10.0.0.0/8' }
    )
} | ConvertTo-Json -Depth 5

Invoke-MgGraphRequest -Method PATCH `
  -Uri 'https://graph.microsoft.com/beta/networkAccess/forwardingProfiles/<profile-id>/policies/<bypass-policy-id>' `
  -Body $bypass

# Common bypass candidates:
# - Windows Update / Microsoft Update endpoints (already excluded by default profile)
# - On-premises Active Directory domain traffic
# - Legacy apps that break under TLS inspection

// Detect TLS inspection bypass attempts — clients sending traffic directly without GSA tunnel
// Compare expected users with those appearing in NetworkAccessTraffic
let gsa_users = NetworkAccessTraffic
| where TimeGenerated > ago(1d)
| where TrafficType == 'internet'
| summarize by UserPrincipalName;

// Users who should be on GSA (from a group) but are absent from traffic logs
// This requires a reference list — substitute with your managed device group export
let managed_users = datatable(UserPrincipalName: string)
[  'alice@contoso.com', 'bob@contoso.com', 'carol@contoso.com'  ];

managed_users
| where UserPrincipalName !in (gsa_users)
| project UserPrincipalName, Status = 'No GSA traffic in last 24h'
